import{_ as b,$ as y,r as f,o as q,I as x,d as l,e as o,a2 as h,j as p,n as k,b as n}from"./index.2fed4629.js";const S={class:"help-container"},A={key:0,class:"toc"},T={key:1,class:"help-footer"},P={__name:"pixelPower",setup(I){const m=y(),i=f(m.query.autoScroll==="true");let d=null;const c=e=>{var t;if(!i.value&&e.target.tagName==="A"&&((t=e.target.getAttribute("href"))==null?void 0:t.startsWith("#"))){e.preventDefault();const s=e.target.getAttribute("href").slice(1),a=document.getElementById(s);a&&a.scrollIntoView({behavior:"smooth",block:"start"})}},g=()=>{const e=document.querySelector(".help-page");if(!e)return;let t=1,s=1,a=0;const v=360,r=()=>{const w=e.scrollHeight-e.clientHeight,u=e.scrollTop;if(a>0){a--,d=requestAnimationFrame(r);return}t===1?(e.scrollTop+=s,u>=w-10&&(a=v,t=-1,s=100)):(e.scrollTop-=s,u<=10&&(a=v,t=1,s=1)),d=requestAnimationFrame(r)};d=requestAnimationFrame(r)};return q(()=>{document.addEventListener("click",c),i.value&&setTimeout(g,1e3)}),x(()=>{document.removeEventListener("click",c),d&&cancelAnimationFrame(d)}),(e,t)=>(n(),l("div",{class:k(["help-page",{"auto-scroll-mode":i.value}])},[o("div",S,[t[2]||(t[2]=o("header",{id:"top",class:"help-header"},[o("h1",{class:"crt-text-green"},"\u{1F3A8} PIXEL POWER: AI ART COLLAB"),o("p",{class:"subtitle"},"Create Amazing AI Art Together!")],-1)),i.value?p("",!0):(n(),l("nav",A,[...t[0]||(t[0]=[h('<h2 class="crt-text-yellow" data-v-044e4682>Quick Navigation</h2><ul data-v-044e4682><li data-v-044e4682><a href="#basics" data-v-044e4682>Game Basics</a></li><li data-v-044e4682><a href="#commands" data-v-044e4682>How to Play</a></li><li data-v-044e4682><a href="#limits" data-v-044e4682>Submission Limits</a></li><li data-v-044e4682><a href="#dictionary" data-v-044e4682>Word Rules</a></li><li data-v-044e4682><a href="#scoring" data-v-044e4682>Scrabble Scoring</a></li><li data-v-044e4682><a href="#generation" data-v-044e4682>Image Generation</a></li><li data-v-044e4682><a href="#tips" data-v-044e4682>Pro Tips</a></li></ul>',2)])])),t[3]||(t[3]=h('<section id="basics" class="help-section" data-v-044e4682><h2 class="crt-text-green" data-v-044e4682>\u{1F4D6} Game Basics</h2><div class="content-block" data-v-044e4682><h3 data-v-044e4682>What is Pixel Power?</h3><p data-v-044e4682>Pixel Power is a collaborative AI art creation game where the Twitch community works together to generate unique images! Submit words in chat and the AI creates a stunning video game-style artwork based on ALL submitted words combined!</p><h3 data-v-044e4682>How It Works</h3><ol data-v-044e4682><li data-v-044e4682><strong data-v-044e4682>Round System:</strong> Game has 2-3min rounds, each accepting words that start with a specific letter</li><li data-v-044e4682><strong data-v-044e4682>Submit Words:</strong> When each round starts, the starting letter is displayed on stream.<br data-v-044e4682> Type <code class="crt-text-yellow" data-v-044e4682>!pp [word-with-matching-first-letter]</code> in chat</li><li data-v-044e4682><strong data-v-044e4682>Image Generated:</strong> AI creates art when 100 words reached every 4-6 hours<br data-v-044e4682>(or in the very unlikely event 24 hours pass without collecting enough words)</li><li data-v-044e4682><strong data-v-044e4682>Earn Rewards:</strong> Get zCubes based on a mod&#39;d Scrabble score \xD7 8 multiplier!</li></ol></div><a href="#top" class="back-to-top" data-v-044e4682>\u2191 Back to Top</a></section><section id="commands" class="help-section" data-v-044e4682><h2 class="crt-text-green" data-v-044e4682>\u{1F4AC} How to Play</h2><div class="command-list" data-v-044e4682><div class="command-item" data-v-044e4682><h3 data-v-044e4682><code class="crt-text-yellow" data-v-044e4682>!pp [word]</code></h3><p data-v-044e4682>Submit a single dictionary word to the collection</p><p data-v-044e4682><strong data-v-044e4682>Examples:</strong></p><ul data-v-044e4682><li data-v-044e4682><code data-v-044e4682>!pp dragon</code> - Submit the word &quot;dragon&quot;</li><li data-v-044e4682><code data-v-044e4682>!pp sword</code> - Submit the word &quot;sword&quot;</li><li data-v-044e4682><code data-v-044e4682>!pp crystal</code> - Submit the word &quot;crystal&quot;</li></ul><div class="note" data-v-044e4682><strong data-v-044e4682>\u26A0\uFE0F Important:</strong> Only ONE word at a time! Words like &quot;fire dragon&quot; won&#39;t work. Submit them separately: <code data-v-044e4682>!pp fire</code> then <code data-v-044e4682>!pp dragon</code></div></div><div class="command-item" data-v-044e4682><h3 data-v-044e4682>What Happens After Submission?</h3><ol data-v-044e4682><li data-v-044e4682><strong data-v-044e4682>Validation:</strong> Word is checked against dictionary API</li><li data-v-044e4682><strong data-v-044e4682>Scoring:</strong> Scrabble score is calculated (see Scoring section)</li><li data-v-044e4682><strong data-v-044e4682>Collection Update:</strong>per round countdown (e.g. 3 words left)</li></ol></div></div><a href="#top" class="back-to-top" data-v-044e4682>\u2191 Back to Top</a></section><section id="limits" class="help-section" data-v-044e4682><h2 class="crt-text-green" data-v-044e4682>\u23F1\uFE0F Submission Limits</h2><div class="content-block" data-v-044e4682><h3 data-v-044e4682>Personal Timer System</h3><p data-v-044e4682>Pixel Power uses a <strong data-v-044e4682>personal timer system</strong> to keep things fair and give everyone a chance to contribute across different time zones:</p><div class="limit-box daily" data-v-044e4682><h4 data-v-044e4682>\u{1F4C5} Daily Allowance: 12 Words</h4><ul data-v-044e4682><li data-v-044e4682><strong data-v-044e4682>12 words per 25-hour cycle</strong> per user</li><li data-v-044e4682>Your personal timer starts when you submit your <strong data-v-044e4682>first word</strong></li><li data-v-044e4682>After 25 hours, your allowance resets to 12 words</li><li data-v-044e4682>Each person has their own independent timer!</li></ul><div class="example" data-v-044e4682><strong data-v-044e4682>Example:</strong><ul data-v-044e4682><li data-v-044e4682>\u{1F550} Monday 2:00 PM - You submit your first word (timer starts, 11 left)</li><li data-v-044e4682>\u{1F550} Monday 8:00 PM - You use all 12 words (0 left)</li><li data-v-044e4682>\u{1F6AB} Monday 9:00 PM - Try to submit \u2192 Over-limit penalty applies</li><li data-v-044e4682>\u2705 Tuesday 3:00 PM - Your 25h timer expires, reset to 12 words!</li></ul></div></div><div class="limit-box hourly" data-v-044e4682><h4 data-v-044e4682>\u{1F493} Personal Cooldown: 22 Minutes</h4><ul data-v-044e4682><li data-v-044e4682><strong data-v-044e4682>22-minute cooldown</strong> between each word submission</li><li data-v-044e4682>Submitting during cooldown triggers <strong data-v-044e4682>Hurry-Tax</strong> penalty</li><li data-v-044e4682>Hurry-Tax stacks: 50% \u2192 25% \u2192 12.5% of normal points</li><li data-v-044e4682>After 5 hurry-tax violations: 6-hour timeout!</li></ul><div class="example" data-v-044e4682><strong data-v-044e4682>Example:</strong><ul data-v-044e4682><li data-v-044e4682>\u{1F550} 12:00 PM - Submit &quot;dragon&quot; (cooldown starts, expires 12:22)</li><li data-v-044e4682>\u{1F6AB} 12:10 PM - Submit &quot;sword&quot; \u2192 \u23F1\uFE0F Hurry-Tax #1 (50% points, cooldown resets to 12:32)</li><li data-v-044e4682>\u{1F6AB} 12:20 PM - Submit &quot;fire&quot; \u2192 \u23F1\uFE0F Hurry-Tax #2 (25% points, cooldown resets to 12:42)</li><li data-v-044e4682>\u2705 12:42 PM - Cooldown expires, submit normally (hurry-tax count resets)!</li></ul></div></div><h3 data-v-044e4682>Over-Limit Submissions</h3><p data-v-044e4682>You can <strong data-v-044e4682>still submit</strong> after using all 12 words, but with penalties:</p><ul data-v-044e4682><li data-v-044e4682>\u26A0\uFE0F <strong data-v-044e4682>Stacking penalty:</strong> 50% \u2192 33% \u2192 25% \u2192 ... of normal points</li><li data-v-044e4682>\u23F0 <strong data-v-044e4682>Reset delay:</strong> Each over-limit word adds hours to your reset timer</li><li data-v-044e4682>Formula: 1st over = +1h, 2nd = +2h more, 3rd = +3h more... (triangular)</li></ul><div class="pro-tip" data-v-044e4682><strong data-v-044e4682>\u{1F4A1} Strategy:</strong> Pace yourself! Spreading your 12 words over time is better than burning through them all at once with hurry-tax penalties. </div><h3 data-v-044e4682>What Messages Will You See?</h3><div class="limit-messages" data-v-044e4682><div class="message-box" data-v-044e4682><code class="crt-text-yellow" data-v-044e4682>\u23F1\uFE0F hurry #1 (50%)</code><p data-v-044e4682>You submitted during your 22-minute cooldown. Points reduced, but word still counts!</p></div><div class="message-box" data-v-044e4682><code class="crt-text-red" data-v-044e4682>\u26A0\uFE0F Over-limit: 50% reward, +1h delay</code><p data-v-044e4682>You&#39;ve used all 12 words. Submission accepted with penalty and delayed reset.</p></div><div class="message-box" data-v-044e4682><code class="crt-text-red" data-v-044e4682>\u{1F7E8} YELLOW card!</code><p data-v-044e4682>3 invalid words in a row = half points on your next submission.</p></div></div></div><a href="#top" class="back-to-top" data-v-044e4682>\u2191 Back to Top</a></section><section id="dictionary" class="help-section" data-v-044e4682><h2 class="crt-text-green" data-v-044e4682>\u{1F4DA} Word Rules</h2><div class="content-block" data-v-044e4682><h3 data-v-044e4682>Valid Words</h3><p data-v-044e4682>All words are validated using a real English dictionary API. To be accepted, your word must:</p><ul data-v-044e4682><li data-v-044e4682>\u2705 Be a real English word</li><li data-v-044e4682>\u2705 Be found in the dictionary</li><li data-v-044e4682>\u2705 Be a single word (some exceptions apply like &quot;black hole&quot;)</li><li data-v-044e4682>\u2705 Be spelled correctly</li></ul><h3 data-v-044e4682>Invalid Words</h3><ul data-v-044e4682><li data-v-044e4682>\u274C Multiple words: &quot;fire dragon&quot; \u2192 Use separately</li><li data-v-044e4682>\u274C Misspellings: &quot;dragn&quot; \u2192 Won&#39;t be accepted</li><li data-v-044e4682>\u274C Made-up words: &quot;flibbertigibbet&quot; \u2192 Depends on dictionary!</li><li data-v-044e4682>\u274C Numbers/symbols: &quot;dr4gon&quot; \u2192 Letters only</li><li data-v-044e4682>\u274C Profanity/Sexual Content: let&#39;s keep it family-friendly!</li></ul><div class="pro-tip" data-v-044e4682><strong data-v-044e4682>\u{1F4A1} Fun Fact:</strong> The dictionary includes some quirky but real words! Try &quot;defenestration&quot; (throwing someone out a window) or &quot;petrichor&quot; (the smell of rain on dry earth). </div><h3 data-v-044e4682>What Happens if Word is Invalid?</h3><div class="message-box" data-v-044e4682><code class="crt-text-red" data-v-044e4682>\u26A0\uFE0F @username \u{1F7E8} 1/3 fails: that is not a dictionary word</code><p data-v-044e4682>after three invalid words, a \u{1F7E8} yellow card is issued that will give half points on your next submission.</p><p data-v-044e4682>any &quot;proper&quot; word will reset the counter</p></div></div><a href="#top" class="back-to-top" data-v-044e4682>\u2191 Back to Top</a></section><section id="scoring" class="help-section" data-v-044e4682><h2 class="crt-text-green" data-v-044e4682>\u{1F3AF} Scrabble Scoring</h2><div class="content-block" data-v-044e4682><h3 data-v-044e4682>How Scoring Works</h3><p data-v-044e4682>Each word earns a Scrabble score based on letter values, multiplied by 8! Higher scores mean more zCubes. This rewards creative vocabulary!</p><div class="score-table" data-v-044e4682><h4 data-v-044e4682>Letter Values</h4><table data-v-044e4682><tr data-v-044e4682><th data-v-044e4682>Points</th><th data-v-044e4682>Letters</th></tr><tr data-v-044e4682><td class="score" data-v-044e4682>0</td><td data-v-044e4682>X, Z</td></tr><tr data-v-044e4682><td class="score" data-v-044e4682>1</td><td data-v-044e4682>A, E, I, O, U, L, N, S, T, R, Q</td></tr><tr data-v-044e4682><td class="score" data-v-044e4682>2</td><td data-v-044e4682>D, G</td></tr><tr data-v-044e4682><td class="score" data-v-044e4682>3</td><td data-v-044e4682>B, C, M, P</td></tr><tr data-v-044e4682><td class="score" data-v-044e4682>4</td><td data-v-044e4682>F, H, V, W, Y</td></tr><tr data-v-044e4682><td class="score" data-v-044e4682>5</td><td data-v-044e4682>K</td></tr><tr data-v-044e4682><td class="score" data-v-044e4682>8</td><td data-v-044e4682>J</td></tr></table></div></div><a href="#top" class="back-to-top" data-v-044e4682>\u2191 Back to Top</a></section><section id="generation" class="help-section" data-v-044e4682><h2 class="crt-text-green" data-v-044e4682>\u{1F3A8} Image Generation</h2><div class="content-block" data-v-044e4682><h3 data-v-044e4682>When Does Generation Happen?</h3><p data-v-044e4682>AI image generation is triggered by ONE of these conditions:</p><div class="trigger-conditions" data-v-044e4682><div class="trigger" data-v-044e4682><h4 class="crt-text-yellow" data-v-044e4682>\u{1F3AF} 100 Words Collected</h4><p data-v-044e4682>When the 100th word is submitted, image generation starts immediately!</p></div><div class="trigger" data-v-044e4682><h4 class="crt-text-cyan" data-v-044e4682>\u23F0 24-Hour Timer Expires</h4><p data-v-044e4682>If 100 words aren&#39;t reached in 24 hours, the AI generates from whatever words are available (even if just 5 or 10 words!).</p></div></div><h3 data-v-044e4682>The Generation Process</h3><ol data-v-044e4682><li data-v-044e4682><strong data-v-044e4682>Collection Completes:</strong> 100 words OR timer expires</li><li data-v-044e4682><strong data-v-044e4682>Prompt Building:</strong> All words combined into AI prompt</li><li data-v-044e4682><strong data-v-044e4682>AI Generation:</strong> Nano Banana creates the image</li><li data-v-044e4682><strong data-v-044e4682>Style Applied:</strong> &quot;comic book, video game, concept art&quot;</li><li data-v-044e4682><strong data-v-044e4682>Display:</strong> Generated image appears in carousel</li><li data-v-044e4682><strong data-v-044e4682>Reset:</strong> New session begins with 0/100 words!</li></ol><h3 data-v-044e4682>What Makes the Art Unique?</h3><p data-v-044e4682>The AI combines ALL submitted words into a single coherent image with these characteristics:</p><ul data-v-044e4682><li data-v-044e4682>\u{1F58C}\uFE0F Comic book style</li><li data-v-044e4682>\u{1F3AE} Video game theme</li><li data-v-044e4682>\u2728 Cinematic lighting and atmosphere</li><li data-v-044e4682>\u{1F5BC}\uFE0F Ultra-detailed, intricate elements</li><li data-v-044e4682>\u{1F3AD} Dramatic composition</li><li data-v-044e4682>\u{1F308} Rich colors and depth of field</li></ul><div class="example" data-v-044e4682><strong data-v-044e4682>Example Prompt:</strong><p data-v-044e4682>If words submitted are: dragon, sword, crystal, fire, castle...</p><p class="crt-text-cyan" data-v-044e4682>&quot;dragon, sword, crystal, fire, castle, video game art, concept art, game asset, rendered in Unreal Engine, cinematic lighting, dramatic atmosphere, masterpiece, best quality, ultra detailed&quot;</p></div><div class="pro-tip" data-v-044e4682><strong data-v-044e4682>\u{1F4A1} Collaboration Tip:</strong> Coordinate with other viewers! Plan themed collections like &quot;underwater adventure&quot; or &quot;space exploration&quot; for cohesive, amazing results! </div></div><a href="#top" class="back-to-top" data-v-044e4682>\u2191 Back to Top</a></section><section id="tips" class="help-section" data-v-044e4682><h2 class="crt-text-green" data-v-044e4682>\u{1F3C6} Pro Tips &amp; Strategy</h2><div class="tips-grid" data-v-044e4682><div class="tip-card" data-v-044e4682><h3 data-v-044e4682>\u{1F3AD} Theme Your Words</h3><p data-v-044e4682>Coordinate with chat! Themed collections create better, more cohesive AI art.</p></div><div class="tip-card" data-v-044e4682><h3 data-v-044e4682>\u{1F31F} Be Creative</h3><p data-v-044e4682>Don&#39;t just use common words! &quot;ETHEREAL&quot; or &quot;LUMINOUS&quot; make for better art than &quot;THING&quot; or &quot;STUFF&quot;.</p></div><div class="tip-card" data-v-044e4682><h3 data-v-044e4682>\u{1F91D} Collaborate</h3><p data-v-044e4682>Discuss in chat! Build on others&#39; words to create a cohesive concept.</p></div><div class="tip-card" data-v-044e4682><h3 data-v-044e4682>\u{1F3A8} Visual Thinking</h3><p data-v-044e4682>Think about how words will look combined. &quot;DRAGON&quot; + &quot;FIRE&quot; + &quot;MOUNTAIN&quot; = Epic scene!</p></div><div class="tip-card" data-v-044e4682><h3 data-v-044e4682>\u26A1 Be Quick but Thoughtful</h3><p data-v-044e4682>Don&#39;t waste submissions on low-value, common words when you have limited tries!</p></div></div><a href="#top" class="back-to-top" data-v-044e4682>\u2191 Back to Top</a></section>',7)),i.value?p("",!0):(n(),l("footer",T,[...t[1]||(t[1]=[o("p",{class:"crt-text-green"},"Ready to create amazing art together? Jump in chat and type !pp [word]! \u{1F3A8}\u2728",-1),o("p",null,[o("a",{href:"/art",class:"back-link"},"\u2190 Back to Pixel Power")],-1)])]))])],2))}},W=b(P,[["__scopeId","data-v-044e4682"]]);export{W as default};
